const e=JSON.parse(`[{"id":1,"section":"A","theme":"Daily activities","question":"Quelle image correspond le mieux à l'enregistrement ?","options":[{"id":"A","text":"Une personne court dans le parc","image_prompt":"A person running in a green park, sunny day"},{"id":"B","text":"Une personne fait du vélo","image_prompt":"A person riding a bicycle on a city path"},{"id":"C","text":"Une personne nage","image_prompt":"A person swimming in a blue pool"},{"id":"D","text":"Une personne marche avec un chien","image_prompt":"A person walking a golden retriever in a park"}],"correct":0,"transcript_fr":"J'adore commencer ma journée par un petit footing au parc quand il fait beau.","transcript_en":"I love starting my day with a quick jog in the park when the weather is nice.","points":[{"point":1,"male_lines":["J'adore commencer ma journée par un petit footing au parc quand il fait beau."],"female_lines":[]}]},{"id":2,"section":"A","theme":"Transportation","question":"Quelle image correspond le mieux à l'enregistrement ?","options":[{"id":"A","text":"Un autobus scolaire","image_prompt":"A yellow school bus on a street"},{"id":"B","text":"Un taxi","image_prompt":"A yellow taxi cab in the city"},{"id":"C","text":"Un métro","image_prompt":"A subway train arriving at a station"},{"id":"D","text":"Un avion","image_prompt":"An airplane taking off from a runway"}],"correct":2,"transcript_fr":"Je prends toujours le métro pour aller travailler, c'est plus rapide que l'autobus.","transcript_en":"I always take the subway to go to work, it's faster than the bus.","points":[{"point":1,"male_lines":["Je prends toujours le métro pour aller travailler, c'est plus rapide que l'autobus."],"female_lines":[]}]},{"id":3,"section":"A","theme":"Food and dining","question":"Quelle image correspond le mieux à l'enregistrement ?","options":[{"id":"A","text":"Une pizza","image_prompt":"A delicious pizza with cheese and pepperoni"},{"id":"B","text":"Un sandwich","image_prompt":"A fresh sandwich with lettuce and tomato"},{"id":"C","text":"Une salade","image_prompt":"A fresh green salad in a bowl"},{"id":"D","text":"Un hamburger","image_prompt":"A juicy hamburger with fries on the side"}],"correct":3,"transcript_fr":"Pour le dîner, je vais me commander un bon hamburger avec des frites.","transcript_en":"For lunch, I'm going to order myself a good hamburger with fries.","points":[{"point":1,"male_lines":["Pour le dîner, je vais me commander un bon hamburger avec des frites."],"female_lines":[]}]},{"id":4,"section":"A","theme":"Weather","question":"Quelle image correspond le mieux à l'enregistrement ?","options":[{"id":"A","text":"Il neige","image_prompt":"Snow falling on a winter landscape"},{"id":"B","text":"Il pleut","image_prompt":"Rain falling on a city street with umbrellas"},{"id":"C","text":"Il fait soleil","image_prompt":"Bright sunny day with clear blue sky"},{"id":"D","text":"Il y a du vent","image_prompt":"Wind blowing through trees on a stormy day"}],"correct":1,"transcript_fr":"N'oublie pas ton parapluie, il pleut des cordes dehors!","transcript_en":"Don't forget your umbrella, it's raining cats and dogs outside!","points":[{"point":1,"male_lines":["N'oublie pas ton parapluie, il pleut des cordes dehors!"],"female_lines":[]}]},{"id":5,"section":"A","theme":"Shopping","question":"Quelle image correspond le mieux à l'enregistrement ?","options":[{"id":"A","text":"Un supermarché","image_prompt":"Interior of a grocery supermarket with aisles"},{"id":"B","text":"Une pharmacie","image_prompt":"A pharmacy storefront with green cross"},{"id":"C","text":"Une librairie","image_prompt":"A bookstore with shelves full of books"},{"id":"D","text":"Un magasin de vêtements","image_prompt":"A clothing store with racks of clothes"}],"correct":0,"transcript_fr":"Je dois passer au supermarché acheter du lait et du pain pour ce soir.","transcript_en":"I need to stop by the supermarket to buy milk and bread for tonight.","points":[{"point":1,"male_lines":["Je dois passer au supermarché acheter du lait et du pain pour ce soir."],"female_lines":[]}]},{"id":6,"section":"A","theme":"Time","question":"Quelle image correspond le mieux à l'enregistrement ?","options":[{"id":"A","text":"Une horloge murale","image_prompt":"A round wall clock showing time"},{"id":"B","text":"Une montre-bracelet","image_prompt":"A wristwatch on someone's wrist"},{"id":"C","text":"Un réveil","image_prompt":"An alarm clock on a bedside table"},{"id":"D","text":"Un calendrier","image_prompt":"A wall calendar showing the month"}],"correct":2,"transcript_fr":"Mon réveil sonne à six heures tous les matins, c'est insupportable!","transcript_en":"My alarm clock rings at six o'clock every morning, it's unbearable!","points":[{"point":1,"male_lines":["Mon réveil sonne à six heures tous les matins, c'est insupportable!"],"female_lines":[]}]},{"id":7,"section":"B","theme":"Making plans","question":"Que décident les interlocuteurs de faire ?","options":[{"id":"A","text":"Aller au cinéma","image_prompt":"Movie theater with popcorn"},{"id":"B","text":"Dîner au restaurant","image_prompt":"Restaurant table with food"},{"id":"C","text":"Faire une promenade","image_prompt":"People walking in a park"},{"id":"D","text":"Rester à la maison","image_prompt":"Cozy living room interior"}],"correct":1,"transcript_fr":"Marc: Salut Julie, tu es libre ce soir? Julie: Oui, pourquoi? Marc: Je me demandais si tu voulais aller manger quelque part. Julie: Bonne idée! Où est-ce qu'on va? Marc: Il y a un nouveau restaurant italien sur la rue Saint-Denis. Julie: Parfait, j'adore la cuisine italienne. Marc: On se retrouve là-bas à sept heures? Julie: D'accord, à ce soir alors!","transcript_en":"Marc: Hi Julie, are you free tonight? Julie: Yes, why? Marc: I was wondering if you wanted to go eat somewhere. Julie: Good idea! Where are we going? Marc: There's a new Italian restaurant on Saint-Denis street. Julie: Perfect, I love Italian cuisine. Marc: Shall we meet there at seven? Julie: Okay, see you tonight then!","points":[{"point":1,"male_lines":["Salut Julie, tu es libre ce soir?","Je me demandais si tu voulais aller manger quelque part."],"female_lines":["Oui, pourquoi?","Bonne idée! Où est-ce qu'on va?"]},{"point":2,"male_lines":["Il y a un nouveau restaurant italien sur la rue Saint-Denis.","On se retrouve là-bas à sept heures?"],"female_lines":["Parfait, j'adore la cuisine italienne.","D'accord, à ce soir alors!"]}]},{"id":8,"section":"B","theme":"Asking for directions","question":"Où la femme veut-elle aller ?","options":[{"id":"A","text":"À la banque","image_prompt":"Bank building exterior"},{"id":"B","text":"À la poste","image_prompt":"Post office building"},{"id":"C","text":"À la bibliothèque","image_prompt":"Public library building"},{"id":"D","text":"À l'hôtel de ville","image_prompt":"City hall building"}],"correct":2,"transcript_fr":"Sophie: Excusez-moi monsieur, je cherche la bibliothèque municipale. Thomas: La bibliothèque? Elle est juste au coin de la rue, là-bas. Sophie: C'est loin à pied? Thomas: Non, pas du tout. C'est à cinq minutes d'ici. Sophie: Je dois tourner à gauche ou à droite? Thomas: Continuez tout droit, puis tournez à droite au feu rouge. Sophie: Merci beaucoup pour votre aide! Thomas: Je vous en prie, bonne journée!","transcript_en":"Sophie: Excuse me sir, I'm looking for the municipal library. Thomas: The library? It's just around the corner, over there. Sophie: Is it far to walk? Thomas: No, not at all. It's five minutes from here. Sophie: Should I turn left or right? Thomas: Continue straight ahead, then turn right at the red light. Sophie: Thank you very much for your help! Thomas: You're welcome, have a good day!","points":[{"point":1,"male_lines":["La bibliothèque? Elle est juste au coin de la rue, là-bas.","Non, pas du tout. C'est à cinq minutes d'ici."],"female_lines":["Excusez-moi monsieur, je cherche la bibliothèque municipale.","C'est loin à pied?"]},{"point":2,"male_lines":["Continuez tout droit, puis tournez à droite au feu rouge.","Je vous en prie, bonne journée!"],"female_lines":["Je dois tourner à gauche ou à droite?","Merci beaucoup pour votre aide!"]}]},{"id":9,"section":"B","theme":"Shopping conversation","question":"Quelle taille la cliente cherche-t-elle ?","options":[{"id":"A","text":"Petite","image_prompt":"Small size clothing label"},{"id":"B","text":"Moyenne","image_prompt":"Medium size clothing label"},{"id":"C","text":"Grande","image_prompt":"Large size clothing label"},{"id":"D","text":"Extra-grande","image_prompt":"Extra large size clothing label"}],"correct":1,"transcript_fr":"Vendeur: Bonjour madame, puis-je vous aider? Cliente: Oui, je cherche un manteau comme celui-ci en taille moyenne. Vendeur: Attendez, je vais vérifier en arrière. Cliente: Prenez votre temps. Vendeur: Malheureusement, nous n'avons plus de moyen. Il nous reste du grand. Cliente: Le grand sera trop large pour moi. Vendeur: Je peux commander votre taille, ça arrivera demain. Cliente: D'accord, je repasserai demain alors.","transcript_en":"Salesman: Hello madam, may I help you? Customer: Yes, I'm looking for a coat like this one in medium size. Salesman: Wait, I'll check in the back. Customer: Take your time. Salesman: Unfortunately, we don't have medium anymore. We have large left. Customer: Large will be too wide for me. Salesman: I can order your size, it will arrive tomorrow. Customer: Okay, I'll come back tomorrow then.","points":[{"point":1,"male_lines":["Bonjour madame, puis-je vous aider?","Attendez, je vais vérifier en arrière."],"female_lines":["Oui, je cherche un manteau comme celui-ci en taille moyenne.","Prenez votre temps."]},{"point":2,"male_lines":["Malheureusement, nous n'avons plus de moyen. Il nous reste du grand.","Je peux commander votre taille, ça arrivera demain."],"female_lines":["Le grand sera trop large pour moi.","D'accord, je repasserai demain alors."]}]},{"id":10,"section":"B","theme":"Phone call","question":"Pourquoi la femme téléphone-t-elle ?","options":[{"id":"A","text":"Pour prendre rendez-vous chez le médecin","image_prompt":"Doctor appointment calendar"},{"id":"B","text":"Pour annuler une réservation","image_prompt":"Cancellation notice"},{"id":"C","text":"Pour demander des informations","image_prompt":"Information desk"},{"id":"D","text":"Pour faire une réclamation","image_prompt":"Customer complaint form"}],"correct":0,"transcript_fr":"Réceptionniste: Clinique médicale Saint-Laurent, bonjour. Patient: Bonjour, je voudrais prendre rendez-vous avec le docteur Tremblay. Réceptionniste: C'est pour quand? Patient: Le plus tôt possible, j'ai mal à la gorge depuis trois jours. Réceptionniste: Il reste une place demain à quatorze heures. Patient: Demain à quatorze heures, c'est parfait. Réceptionniste: Votre nom s'il vous plaît? Patient: Marie Lefebvre. Réceptionniste: C'est noté, au revoir madame.","transcript_en":"Receptionist: Saint-Laurent Medical Clinic, hello. Patient: Hello, I would like to make an appointment with Dr. Tremblay. Receptionist: For when? Patient: As soon as possible, I've had a sore throat for three days. Receptionist: There's one spot left tomorrow at two o'clock. Patient: Tomorrow at two o'clock, that's perfect. Receptionist: Your name please? Patient: Marie Lefebvre. Receptionist: It's noted, goodbye madam.","points":[{"point":1,"male_lines":["Clinique médicale Saint-Laurent, bonjour.","C'est pour quand?"],"female_lines":["Bonjour, je voudrais prendre rendez-vous avec le docteur Tremblay.","Le plus tôt possible, j'ai mal à la gorge depuis trois jours."]},{"point":2,"male_lines":["Il reste une place demain à quatorze heures.","Votre nom s'il vous plaît?"],"female_lines":["Demain à quatorze heures, c'est parfait.","Marie Lefebvre."]}]},{"id":11,"section":"C","theme":"Train station announcement","question":"Quelle information est donnée dans cette annonce ?","options":[{"id":"A","text":"Un retard de train","image_prompt":"Delayed train sign"},{"id":"B","text":"Un changement de quai","image_prompt":"Platform change announcement"},{"id":"C","text":"Une annulation de service","image_prompt":"Service cancelled sign"},{"id":"D","text":"Une promotion spéciale","image_prompt":"Special promotion poster"}],"correct":1,"transcript_fr":"Attention passagers du train numéro quatre-vingt-cinq à destination de Québec. En raison de travaux sur la voie, le départ se fera désormais du quai numéro douze au lieu du quai numéro huit. Nous vous prions de bien vouloir vous diriger immédiatement vers le quai douze. Le départ est maintenu à quatorze heures trente. Nous vous remercions de votre compréhension et vous souhaitons un bon voyage.","transcript_en":"Attention passengers of train number eighty-five to Quebec. Due to track work, departure will now be from platform number twelve instead of platform number eight. We kindly ask you to proceed immediately to platform twelve. Departure is maintained at two thirty. We thank you for your understanding and wish you a pleasant journey.","points":[{"point":1,"male_lines":["Attention passagers du train numéro quatre-vingt-cinq à destination de Québec.","En raison de travaux sur la voie, le départ se fera désormais du quai numéro douze au lieu du quai numéro huit."],"female_lines":[]},{"point":2,"male_lines":["Nous vous prions de bien vouloir vous diriger immédiatement vers le quai douze.","Le départ est maintenu à quatorze heures trente."],"female_lines":[]},{"point":3,"male_lines":["Nous vous remercions de votre compréhension et vous souhaitons un bon voyage."],"female_lines":[]}]},{"id":12,"section":"C","theme":"Supermarket announcement","question":"Que demande l'annonce aux clients ?","options":[{"id":"A","text":"De quitter le magasin","image_prompt":"Exit sign"},{"id":"B","text":"De se rendre à l'accueil","image_prompt":"Customer service desk"},{"id":"C","text":"De profiter d'une offre spéciale","image_prompt":"Special offer sign"},{"id":"D","text":"D'être prudents sur le sol mouillé","image_prompt":"Wet floor caution sign"}],"correct":3,"transcript_fr":"Mesdames et messieurs, nous attirons votre attention sur le fait que le sol de l'allée des fruits et légumes vient d'être nettoyé. Par mesure de sécurité, veuillez faire attention en marchant dans cette section du magasin. Nos employés sont présents pour vous assister si nécessaire. Nous vous remercions de votre vigilance et vous souhaitons une agréable visite dans notre établissement.","transcript_en":"Ladies and gentlemen, we draw your attention to the fact that the floor of the fruit and vegetable aisle has just been cleaned. For safety reasons, please be careful when walking in this section of the store. Our employees are present to assist you if necessary. We thank you for your vigilance and wish you a pleasant visit to our establishment.","points":[{"point":1,"male_lines":["Mesdames et messieurs, nous attirons votre attention sur le fait que le sol de l'allée des fruits et légumes vient d'être nettoyé.","Par mesure de sécurité, veuillez faire attention en marchant dans cette section du magasin."],"female_lines":[]},{"point":2,"male_lines":["Nos employés sont présents pour vous assister si nécessaire.","Nous vous remercions de votre vigilance et vous souhaitons une agréable visite dans notre établissement."],"female_lines":[]}]},{"id":13,"section":"C","theme":"Museum announcement","question":"Quel changement est annoncé ?","options":[{"id":"A","text":"La fermeture d'une salle","image_prompt":"Room closed sign"},{"id":"B","text":"L'ouverture d'une nouvelle exposition","image_prompt":"New exhibition opening"},{"id":"C","text":"La fin de la visite guidée","image_prompt":"End of guided tour"},{"id":"D","text":"Une réduction pour les étudiants","image_prompt":"Student discount sign"}],"correct":0,"transcript_fr":"Chers visiteurs, nous vous informons que la salle des impressionnistes est temporairement fermée pour cause de rénovation. Les œuvres principales ont été déplacées dans la salle vingt-quatre au deuxième étage. Suivez les flèches oranges pour vous y rendre. Nous vous prions d'excuser ce désagrément temporaire. La réouverture de la salle est prévue pour le mois prochain.","transcript_en":"Dear visitors, we inform you that the Impressionist room is temporarily closed due to renovation. The main works have been moved to room twenty-four on the second floor. Follow the orange arrows to get there. We apologize for this temporary inconvenience. The reopening of the room is scheduled for next month.","points":[{"point":1,"male_lines":["Chers visiteurs, nous vous informons que la salle des impressionnistes est temporairement fermée pour cause de rénovation.","Les œuvres principales ont été déplacées dans la salle vingt-quatre au deuxième étage."],"female_lines":[]},{"point":2,"male_lines":["Suivez les flèches oranges pour vous y rendre.","Nous vous prions d'excuser ce désagrément temporaire.","La réouverture de la salle est prévue pour le mois prochain."],"female_lines":[]}]},{"id":14,"section":"C","theme":"Airport announcement","question":"Quel conseil donne l'annonce ?","options":[{"id":"A","text":"D'arriver plus tôt","image_prompt":"Early arrival sign"},{"id":"B","text":"De vérifier les bagages","image_prompt":"Baggage check sign"},{"id":"C","text":"De se présenter à l'embarquement","image_prompt":"Boarding gate sign"},{"id":"D","text":"D'attendre dans la zone d'attente","image_prompt":"Waiting area sign"}],"correct":2,"transcript_fr":"Passagers du vol Air Canada trois-cinq-zero à destination de Paris, veuillez vous présenter immédiatement à la porte quarante-deux. L'embarquement va commencer dans quelques minutes. Assurez-vous d'avoir votre carte d'embarquement et votre passeport en main. Les passagers voyageant avec de jeunes enfants et les personnes à mobilité réduite seront prioritaires. Merci.","transcript_en":"Passengers of Air Canada flight three-five-zero to Paris, please proceed immediately to gate forty-two. Boarding will begin in a few minutes. Make sure you have your boarding pass and passport in hand. Passengers traveling with young children and people with reduced mobility will have priority. Thank you.","points":[{"point":1,"male_lines":["Passagers du vol Air Canada trois-cinq-zero à destination de Paris, veuillez vous présenter immédiatement à la porte quarante-deux.","L'embarquement va commencer dans quelques minutes."],"female_lines":[]},{"point":2,"male_lines":["Assurez-vous d'avoir votre carte d'embarquement et votre passeport en main.","Les passagers voyageant avec de jeunes enfants et les personnes à mobilité réduite seront prioritaires.","Merci."],"female_lines":[]}]},{"id":15,"section":"C","theme":"Weather alert","question":"Quel temps est annoncé ?","options":[{"id":"A","text":"Une tempête de neige","image_prompt":"Snow storm warning"},{"id":"B","text":"Une canicule","image_prompt":"Heat wave warning"},{"id":"C","text":"Des orages violents","image_prompt":"Thunderstorm warning"},{"id":"D","text":"Du brouillard dense","image_prompt":"Dense fog warning"}],"correct":2,"transcript_fr":"Avis de veille météorologique pour la région de Montréal. Des orages violents accompagnés de fortes pluies et de vents sont prévus pour cet après-midi et cette soirée. Il est recommandé d'éviter les déplacements non essentiels et de rester à l'intérieur. En cas de tonnerre, débranchez vos appareils électroniques. Restez à l'écoute des médias pour les mises à jour.","transcript_en":"Weather watch advisory for the Montreal region. Violent storms accompanied by heavy rain and winds are expected for this afternoon and evening. It is recommended to avoid non-essential travel and stay indoors. In case of thunder, unplug your electronic devices. Stay tuned to the media for updates.","points":[{"point":1,"male_lines":["Avis de veille météorologique pour la région de Montréal.","Des orages violents accompagnés de fortes pluies et de vents sont prévus pour cet après-midi et cette soirée."],"female_lines":[]},{"point":2,"male_lines":["Il est recommandé d'éviter les déplacements non essentiels et de rester à l'intérieur.","En cas de tonnerre, débranchez vos appareils électroniques.","Restez à l'écoute des médias pour les mises à jour."],"female_lines":[]}]},{"id":16,"section":"C","theme":"Library announcement","question":"Quelle nouvelle règle est annoncée ?","options":[{"id":"A","text":"L'interdiction de manger","image_prompt":"No food sign"},{"id":"B","text":"La prolongation des heures d'ouverture","image_prompt":"Extended hours sign"},{"id":"C","text":"Le wifi gratuit","image_prompt":"Free wifi sign"},{"id":"D","text":"Les nouveaux ordinateurs","image_prompt":"New computers available"}],"correct":1,"transcript_fr":"Chers usagers, nous avons le plaisir de vous annoncer que la bibliothèque municipale prolonge ses heures d'ouverture à partir du premier juin. Nous serons désormais ouverts jusqu'à vingt et une heures du lundi au vendredi, et jusqu'à dix-huit heures le samedi. Le dimanche, l'ouverture reste inchangée de treize à dix-sept heures. Profitez-en pour venir étudier ou lire dans le calme!","transcript_en":"Dear users, we are pleased to announce that the municipal library is extending its opening hours starting June first. We will now be open until nine PM Monday through Friday, and until six PM on Saturday. Sunday hours remain unchanged from one to five PM. Take advantage of this to come study or read in peace!","points":[{"point":1,"male_lines":["Chers usagers, nous avons le plaisir de vous annoncer que la bibliothèque municipale prolonge ses heures d'ouverture à partir du premier juin.","Nous serons désormais ouverts jusqu'à vingt et une heures du lundi au vendredi, et jusqu'à dix-huit heures le samedi."],"female_lines":[]},{"point":2,"male_lines":["Le dimanche, l'ouverture reste inchangée de treize à dix-sept heures.","Profitez-en pour venir étudier ou lire dans le calme!"],"female_lines":[]}]},{"id":17,"section":"D","theme":"At the café","question":"Quelle est l'intention du client ?","options":[{"id":"A","text":"Se plaindre du service","image_prompt":"Customer complaining"},{"id":"B","text":"Commander à emporter","image_prompt":"Takeout order"},{"id":"C","text":"Demander des informations sur le menu","image_prompt":"Menu inquiry"},{"id":"D","text":"Réserver une table","image_prompt":"Table reservation"}],"correct":1,"transcript_fr":"Serveur: Bonjour monsieur, vous désirez? Client: Bonjour, je voudrais un café allongé et un croissant, s'il vous plaît. Serveur: Pour manger ici ou à emporter? Client: À emporter, je suis pressé. Serveur: C'est quatre dollars cinquante. Client: Voilà, gardez la monnaie. Serveur: Merci, voici votre commande. Client: Merci, au revoir!","transcript_en":"Server: Hello sir, what would you like? Customer: Hello, I would like a long coffee and a croissant please. Server: For here or to go? Customer: To go, I'm in a hurry. Server: That's four dollars fifty. Customer: Here, keep the change. Server: Thank you, here's your order. Customer: Thanks, goodbye!","points":[{"point":1,"male_lines":["Bonjour monsieur, vous désirez?","Pour manger ici ou à emporter?"],"female_lines":["Bonjour, je voudrais un café allongé et un croissant, s'il vous plaît.","À emporter, je suis pressé."]},{"point":2,"male_lines":["C'est quatre dollars cinquante.","Merci, voici votre commande."],"female_lines":["Voilà, gardez la monnaie.","Merci, au revoir!"]}]},{"id":18,"section":"D","theme":"Job interview","question":"Que veut savoir le recruteur ?","options":[{"id":"A","text":"Les qualifications du candidat","image_prompt":"Qualifications check"},{"id":"B","text":"La disponibilité du candidat","image_prompt":"Availability calendar"},{"id":"C","text":"Les motivations du candidat","image_prompt":"Motivation assessment"},{"id":"D","text":"Les exigences salariales","image_prompt":"Salary negotiation"}],"correct":2,"transcript_fr":"Recruteur: Merci d'être venu aujourd'hui. Pourquoi souhaitez-vous rejoindre notre entreprise? Candidat: J'admire votre engagement envers l'innovation depuis des années. Recruteur: Qu'est-ce qui vous attire particulièrement chez nous? Candidat: Votre politique de développement durable me correspond parfaitement. Recruteur: C'est important pour vous? Candidat: Absolument, je veux travailler pour une entreprise responsable.","transcript_en":"Recruiter: Thank you for coming today. Why do you want to join our company? Candidate: I have admired your commitment to innovation for years. Recruiter: What attracts you particularly to us? Candidate: Your sustainable development policy fits me perfectly. Recruiter: Is that important to you? Candidate: Absolutely, I want to work for a responsible company.","points":[{"point":1,"male_lines":["Merci d'être venu aujourd'hui. Pourquoi souhaitez-vous rejoindre notre entreprise?","Qu'est-ce qui vous attire particulièrement chez nous?"],"female_lines":["J'admire votre engagement envers l'innovation depuis des années.","Votre politique de développement durable me correspond parfaitement."]},{"point":2,"male_lines":["C'est important pour vous?"],"female_lines":["Absolument, je veux travailler pour une entreprise responsable."]}]},{"id":19,"section":"D","theme":"Neighbor complaint","question":"Quelle est l'intention de la femme ?","options":[{"id":"A","text":"Demander de l'aide","image_prompt":"Asking for help"},{"id":"B","text":"Se plaindre du bruit","image_prompt":"Noise complaint"},{"id":"C","text":"Inviter à une fête","image_prompt":"Party invitation"},{"id":"D","text":"Présenter ses excuses","image_prompt":"Apologizing"}],"correct":1,"transcript_fr":"Voisine: Excusez-moi de vous déranger. Voisin: Oui, qu'est-ce qu'il y a? Voisine: C'est au sujet de la musique. Voisin: Elle vous plaît pas? Voisine: Si, mais c'est un peu fort à minuit. Voisin: Ah désolé, je baisserai le volume. Voisine: Merci, c'est gentil. Voisin: Pas de problème, bonne nuit.","transcript_en":"Neighbor: Excuse me for bothering you. Neighbor: Yes, what is it? Neighbor: It's about the music. Neighbor: You don't like it? Neighbor: Yes, but it's a bit loud at midnight. Neighbor: Oh sorry, I'll turn down the volume. Neighbor: Thanks, that's kind. Neighbor: No problem, good night.","points":[{"point":1,"male_lines":["Oui, qu'est-ce qu'il y a?","Elle vous plaît pas?"],"female_lines":["Excusez-moi de vous déranger.","C'est au sujet de la musique."]},{"point":2,"male_lines":["Ah désolé, je baisserai le volume.","Pas de problème, bonne nuit."],"female_lines":["Si, mais c'est un peu fort à minuit.","Merci, c'est gentil."]}]},{"id":20,"section":"D","theme":"Returning an item","question":"Que veut faire le client ?","options":[{"id":"A","text":"Échanger un article","image_prompt":"Item exchange"},{"id":"B","text":"Obtenir un remboursement","image_prompt":"Refund request"},{"id":"C","text":"Acheter un autre article","image_prompt":"Buying another item"},{"id":"D","text":"Réparer un produit défectueux","image_prompt":"Product repair"}],"correct":0,"transcript_fr":"Client: Bonjour, j'ai acheté cette chemise hier mais elle est trop petite. Employé: Vous avez le reçu? Client: Oui, le voici. Employé: Vous voulez la même en plus grand? Client: Oui, en taille large s'il vous plaît. Employé: Attendez, je vais chercher. Client: Merci beaucoup. Employé: Voilà, essayez-la pour être sûr.","transcript_en":"Customer: Hello, I bought this shirt yesterday but it's too small. Employee: Do you have the receipt? Customer: Yes, here it is. Employee: Do you want the same one in a larger size? Customer: Yes, in large size please. Employee: Wait, I'll go get it. Customer: Thank you very much. Employee: Here, try it on to be sure.","points":[{"point":1,"male_lines":["Bonjour, j'ai acheté cette chemise hier mais elle est trop petite.","Vous voulez la même en plus grand?"],"female_lines":["Vous avez le reçu?","Oui, le voici."]},{"point":2,"male_lines":["Attendez, je vais chercher.","Voilà, essayez-la pour être sûr."],"female_lines":["Oui, en taille large s'il vous plaît.","Merci beaucoup."]}]},{"id":21,"section":"D","theme":"Asking for time off","question":"Que demande l'employé ?","options":[{"id":"A","text":"Une augmentation","image_prompt":"Salary raise request"},{"id":"B","text":"Des congés","image_prompt":"Vacation request"},{"id":"C","text":"Un changement d'horaire","image_prompt":"Schedule change"},{"id":"D","text":"Une formation","image_prompt":"Training request"}],"correct":1,"transcript_fr":"Employé: Monsieur, pourriez-vous m'accorder un moment? Patron: Bien sûr, entrez. Employé: Je voudrais prendre une semaine de congé en août. Patron: Quelles dates exactement? Employé: Du quinze au vingt-deux août. Patron: Ça devrait être possible. Employé: Merci, je vous prépare la demande officielle.","transcript_en":"Employee: Sir, could you spare me a moment? Boss: Of course, come in. Employee: I would like to take a week off in August. Boss: What exact dates? Employee: From August fifteenth to twenty-second. Boss: That should be possible. Employee: Thank you, I'll prepare the official request for you.","points":[{"point":1,"male_lines":["Monsieur, pourriez-vous m'accorder un moment?","Quelles dates exactement?"],"female_lines":["Bien sûr, entrez.","Je voudrais prendre une semaine de congé en août."]},{"point":2,"male_lines":["Ça devrait être possible."],"female_lines":["Du quinze au vingt-deux août.","Merci, je vous prépare la demande officielle."]}]},{"id":22,"section":"D","theme":"Making a suggestion","question":"Quelle est l'intention de Pierre ?","options":[{"id":"A","text":"Refuser une invitation","image_prompt":"Refusing invitation"},{"id":"B","text":"Proposer une alternative","image_prompt":"Suggesting alternative"},{"id":"C","text":"Demander un service","image_prompt":"Asking for favor"},{"id":"D","text":"Exprimer son désaccord","image_prompt":"Expressing disagreement"}],"correct":1,"transcript_fr":"Marie: On va au cinéma ce soir, tu viens? Pierre: J'aimerais bien mais j'ai déjà vu ce film. Marie: Dommage, on comptait sur toi. Pierre: Et si on allait au bowling plutôt? Marie: C'est une idée! Pierre: Je connais une nouvelle salle sympa. Marie: Parfait, on se retrouve là-bas à huit heures?","transcript_en":"Marie: We're going to the movies tonight, are you coming? Pierre: I would love to but I've already seen that movie. Marie: Too bad, we were counting on you. Pierre: What if we went bowling instead? Marie: That's an idea! Pierre: I know a nice new place. Marie: Perfect, shall we meet there at eight?","points":[{"point":1,"male_lines":["J'aimerais bien mais j'ai déjà vu ce film.","Et si on allait au bowling plutôt?"],"female_lines":["On va au cinéma ce soir, tu viens?","Dommage, on comptait sur toi."]},{"point":2,"male_lines":["Je connais une nouvelle salle sympa."],"female_lines":["C'est une idée!","Parfait, on se retrouve là-bas à huit heures?"]}]},{"id":23,"section":"E","theme":"Environmental interview","question":"Quel est le sujet principal de l'interview ?","options":[{"id":"A","text":"Le réchauffement climatique","image_prompt":"Global warming"},{"id":"B","text":"Le recyclage","image_prompt":"Recycling program"},{"id":"C","text":"L'agriculture biologique","image_prompt":"Organic farming"},{"id":"D","text":"Les énergies renouvelables","image_prompt":"Renewable energy"}],"correct":3,"transcript_fr":"Journaliste: Merci d'être avec nous aujourd'hui. Expert: C'est un plaisir. Journaliste: Parlez-nous des énergies renouvelables au Québec. Expert: Nous avons un immense potentiel hydroélectrique. Journaliste: Qu'en est-il de l'éolien? Expert: Les projets éoliens se multiplient sur la Côte-Nord. Journaliste: Et le solaire? Expert: Il progresse mais reste complémentaire. Journaliste: L'avenir est prometteur alors?","transcript_en":"Journalist: Thank you for being with us today. Expert: It's a pleasure. Journalist: Tell us about renewable energies in Quebec. Expert: We have immense hydroelectric potential. Journalist: What about wind power? Expert: Wind projects are multiplying on the North Shore. Journalist: And solar? Expert: It's progressing but remains complementary. Journalist: The future is promising then?","points":[{"point":1,"male_lines":["Merci d'être avec nous aujourd'hui.","Parlez-nous des énergies renouvelables au Québec."],"female_lines":["C'est un plaisir.","Nous avons un immense potentiel hydroélectrique."]},{"point":2,"male_lines":["Qu'en est-il de l'éolien?","Et le solaire?"],"female_lines":["Les projets éoliens se multiplient sur la Côte-Nord.","Il progresse mais reste complémentaire."]}]},{"id":24,"section":"E","theme":"Health interview","question":"Quel conseil donne le médecin ?","options":[{"id":"A","text":"Faire plus de sport","image_prompt":"Exercise recommendation"},{"id":"B","text":"Dormir plus","image_prompt":"Sleep more advice"},{"id":"C","text":"Manger équilibré","image_prompt":"Balanced diet"},{"id":"D","text":"Boire plus d'eau","image_prompt":"Drink water advice"}],"correct":0,"transcript_fr":"Journaliste: Docteur, quel est votre conseil pour rester en forme? Médecin: L'activité physique régulière est essentielle. Journaliste: Combien de temps par semaine? Médecin: Au moins cent cinquante minutes d'exercice modéré. Journaliste: C'est accessible à tous? Médecin: Oui, la marche rapide suffit. Journaliste: Pas besoin de s'inscrire au gym? Médecin: Pas nécessairement, l'important est la régularité.","transcript_en":"Journalist: Doctor, what is your advice for staying in shape? Doctor: Regular physical activity is essential. Journalist: How long per week? Doctor: At least one hundred fifty minutes of moderate exercise. Journalist: Is it accessible to everyone? Doctor: Yes, brisk walking is enough. Journalist: No need to sign up at the gym? Doctor: Not necessarily, the important thing is regularity.","points":[{"point":1,"male_lines":["Docteur, quel est votre conseil pour rester en forme?","Combien de temps par semaine?"],"female_lines":["L'activité physique régulière est essentielle.","Au moins cent cinquante minutes d'exercice modéré."]},{"point":2,"male_lines":["C'est accessible à tous?","Pas besoin de s'inscrire au gym?"],"female_lines":["Oui, la marche rapide suffit.","Pas nécessairement, l'important est la régularité."]}]},{"id":25,"section":"E","theme":"Cultural interview","question":"Quel événement est mentionné ?","options":[{"id":"A","text":"Le Festival de Jazz","image_prompt":"Jazz festival"},{"id":"B","text":"Les Francofolies","image_prompt":"Francofolies festival"},{"id":"C","text":"Le Festival Juste pour Rire","image_prompt":"Just for Laughs festival"},{"id":"D","text":"Les Fêtes de la Nouvelle-France","image_prompt":"New France festival"}],"correct":2,"transcript_fr":"Journaliste: Bienvenue dans notre émission culturelle. Artiste: Merci de m'inviter. Journaliste: Vous participez au Festival Juste pour Rire cette année? Artiste: Oui, c'est ma troisième participation. Journaliste: Quel type de spectacle présentez-vous? Artiste: Un one-woman show sur la vie quotidienne. Journaliste: Les billets sont disponibles? Artiste: Oui, sur le site officiel du festival.","transcript_en":"Journalist: Welcome to our cultural show. Artist: Thank you for inviting me. Journalist: Are you participating in the Just for Laughs Festival this year? Artist: Yes, it's my third participation. Journalist: What type of show are you presenting? Artist: A one-woman show about daily life. Journalist: Are tickets available? Artist: Yes, on the festival's official website.","points":[{"point":1,"male_lines":["Bienvenue dans notre émission culturelle.","Vous participez au Festival Juste pour Rire cette année?"],"female_lines":["Merci de m'inviter.","Oui, c'est ma troisième participation."]},{"point":2,"male_lines":["Quel type de spectacle présentez-vous?","Les billets sont disponibles?"],"female_lines":["Un one-woman show sur la vie quotidienne.","Oui, sur le site officiel du festival."]}]},{"id":26,"section":"E","theme":"Technology interview","question":"Quelle innovation est discutée ?","options":[{"id":"A","text":"La voiture électrique","image_prompt":"Electric car"},{"id":"B","text":"Les intelligences artificielles","image_prompt":"Artificial intelligence"},{"id":"C","text":"La réalité virtuelle","image_prompt":"Virtual reality"},{"id":"D","text":"Les drones de livraison","image_prompt":"Delivery drones"}],"correct":1,"transcript_fr":"Journaliste: L'intelligence artificielle transforme notre quotidien. Expert: C'est une révolution en cours. Journaliste: Quels sont les risques selon vous? Expert: La protection des données personnelles. Journaliste: Et les opportunités? Expert: L'amélioration des diagnostics médicaux. Journaliste: Faut-il réguler ce secteur? Expert: Absolument, mais sans freiner l'innovation.","transcript_en":"Journalist: Artificial intelligence is transforming our daily lives. Expert: It's a revolution in progress. Journalist: What are the risks according to you? Expert: The protection of personal data. Journalist: And the opportunities? Expert: The improvement of medical diagnoses. Journalist: Should this sector be regulated? Expert: Absolutely, but without hindering innovation.","points":[{"point":1,"male_lines":["L'intelligence artificielle transforme notre quotidien.","Quels sont les risques selon vous?"],"female_lines":["C'est une révolution en cours.","La protection des données personnelles."]},{"point":2,"male_lines":["Et les opportunités?","Faut-il réguler ce secteur?"],"female_lines":["L'amélioration des diagnostics médicaux.","Absolument, mais sans freiner l'innovation."]}]},{"id":27,"section":"F","theme":"Urban planning debate","question":"Quel est le point de désaccord entre les interlocuteurs ?","options":[{"id":"A","text":"La construction d'un nouveau pont","image_prompt":"Bridge construction debate"},{"id":"B","text":"L'interdiction des voitures en centre-ville","image_prompt":"Car ban downtown"},{"id":"C","text":"L'augmentation des taxes foncières","image_prompt":"Property tax increase"},{"id":"D","text":"La fermeture d'une école","image_prompt":"School closure"}],"correct":1,"transcript_fr":"Martin: Je pense qu'il faut interdire les voitures en centre-ville. Sophie: C'est impossible pour les commerçants! Martin: Les piétons achèteront plus. Sophie: Mais les livraisons? Martin: On peut autoriser les véhicules utilitaires le matin. Sophie: Et les personnes âgées? Martin: Les transports en commun gratuits pour eux. Sophie: Ça coûtera cher à la ville.","transcript_en":"Martin: I think we should ban cars downtown. Sophie: It's impossible for merchants! Martin: Pedestrians will buy more. Sophie: But deliveries? Martin: We can allow utility vehicles in the morning. Sophie: And elderly people? Martin: Free public transit for them. Sophie: It will cost the city a lot.","points":[{"point":1,"male_lines":["Je pense qu'il faut interdire les voitures en centre-ville.","Les piétons achèteront plus."],"female_lines":["C'est impossible pour les commerçants!","Mais les livraisons?"]},{"point":2,"male_lines":["On peut autoriser les véhicules utilitaires le matin.","Les transports en commun gratuits pour eux."],"female_lines":["Et les personnes âgées?","Ça coûtera cher à la ville."]}]},{"id":28,"section":"F","theme":"Education discussion","question":"Quelle solution est proposée pour améliorer l'éducation ?","options":[{"id":"A","text":"Réduire le nombre d'élèves par classe","image_prompt":"Smaller class size"},{"id":"B","text":"Augmenter les salaires des enseignants","image_prompt":"Teacher salary increase"},{"id":"C","text":"Introduire plus de technologie","image_prompt":"Technology in classroom"},{"id":"D","text":"Allonger les heures de cours","image_prompt":"Longer school hours"}],"correct":0,"transcript_fr":"Lucie: Les classes sont trop surchargées actuellement. Thomas: Combien d'élèves en moyenne? Lucie: Trente par classe, c'est ingérable. Thomas: Quelle serait la solution idéale? Lucie: Vingt élèves maximum. Thomas: Ça nécessite plus d'enseignants. Lucie: Oui, mais la qualité s'améliorerait. Thomas: Le gouvernement a les moyens? Lucie: C'est une question de priorité.","transcript_en":"Lucie: Classes are too crowded currently. Thomas: How many students on average? Lucie: Thirty per class, it's unmanageable. Thomas: What would be the ideal solution? Lucie: Twenty students maximum. Thomas: That requires more teachers. Lucie: Yes, but quality would improve. Thomas: Does the government have the means? Lucie: It's a question of priority.","points":[{"point":1,"male_lines":["Combien d'élèves en moyenne?","Quelle serait la solution idéale?"],"female_lines":["Les classes sont trop surchargées actuellement.","Trente par classe, c'est ingérable."]},{"point":2,"male_lines":["Ça nécessite plus d'enseignants.","Le gouvernement a les moyens?"],"female_lines":["Vingt élèves maximum.","Oui, mais la qualité s'améliorerait.","C'est une question de priorité."]}]},{"id":29,"section":"F","theme":"Work-life balance","question":"Quel sujet débattent les interlocuteurs ?","options":[{"id":"A","text":"Le télétravail","image_prompt":"Remote work discussion"},{"id":"B","text":"Les heures supplémentaires","image_prompt":"Overtime discussion"},{"id":"C","text":"Les congés parentaux","image_prompt":"Parental leave"},{"id":"D","text":"La semaine de quatre jours","image_prompt":"Four day work week"}],"correct":3,"transcript_fr":"Émilie: La semaine de quatre jours serait idéale. Marc: Pas sûr que la productivité suive. Émilie: Les employés seraient plus reposés. Marc: Mais les clients exigent une disponibilité cinq jours. Émilie: On peut organiser des équipes en rotation. Marc: Ça complique la gestion. Émilie: L'avantage pour le bien-être vaut le coup.","transcript_en":"Emilie: The four-day work week would be ideal. Marc: Not sure productivity would follow. Emilie: Employees would be more rested. Marc: But clients demand five-day availability. Emilie: We can organize rotating teams. Marc: That complicates management. Emilie: The benefit for well-being is worth it.","points":[{"point":1,"male_lines":["Pas sûr que la productivité suive.","Mais les clients exigent une disponibilité cinq jours."],"female_lines":["La semaine de quatre jours serait idéale.","Les employés seraient plus reposés."]},{"point":2,"male_lines":["Ça complique la gestion."],"female_lines":["On peut organiser des équipes en rotation.","L'avantage pour le bien-être vaut le coup."]}]},{"id":30,"section":"F","theme":"Immigration discussion","question":"Quel aspect de l'immigration est abordé ?","options":[{"id":"A","text":"L'intégration linguistique","image_prompt":"Language integration"},{"id":"B","text":"La reconnaissance des diplômes","image_prompt":"Diploma recognition"},{"id":"C","text":"Le logement","image_prompt":"Housing for immigrants"},{"id":"D","text":"L'emploi","image_prompt":"Employment for immigrants"}],"correct":1,"transcript_fr":"Karim: Mon diplôme d'ingénieur n'est pas reconnu ici. Julie: C'est un problème courant. Karim: Je dois reprendre des études. Julie: Combien de temps ça prend? Karim: Deux ans minimum. Julie: C'est long mais nécessaire. Karim: J'ai quinze ans d'expérience pourtant. Julie: Le système devrait évoluer.","transcript_en":"Karim: My engineering degree isn't recognized here. Julie: It's a common problem. Karim: I have to go back to school. Julie: How long does it take? Karim: Two years minimum. Julie: It's long but necessary. Karim: I have fifteen years of experience though. Julie: The system should evolve.","points":[{"point":1,"male_lines":["Mon diplôme d'ingénieur n'est pas reconnu ici.","Je dois reprendre des études."],"female_lines":["C'est un problème courant.","Combien de temps ça prend?"]},{"point":2,"male_lines":["Deux ans minimum.","J'ai quinze ans d'expérience pourtant."],"female_lines":["C'est long mais nécessaire.","Le système devrait évoluer."]}]},{"id":31,"section":"G","theme":"Climate change debate","question":"Quelle est la position principale défendue dans cet enregistrement ?","options":[{"id":"A","text":"L'urgence d'agir immédiatement","image_prompt":"Climate emergency action"},{"id":"B","text":"L'adaptation progressive","image_prompt":"Gradual adaptation"},{"id":"C","text":"La responsabilité individuelle","image_prompt":"Individual responsibility"},{"id":"D","text":"La technologie comme solution","image_prompt":"Technology solution"}],"correct":0,"transcript_fr":"Animateur: Bienvenue à notre débat sur l'environnement. Nos invités sont le professeur Dubois et Madame Lacroix. Professeur: Merci de nous accueillir. Madame Lacroix: C'est un honneur d'être ici. Animateur: Commençons par l'urgence climatique. Professeur: Nous n'avons plus le temps d'attendre. Madame Lacroix: Je suis d'accord, chaque année compte. Animateur: Quelles solutions proposez-vous? Professeur: La réduction drastique des émissions de carbone. Madame Lacroix: Et une transition énergétique rapide. Animateur: Est-ce réaliste économiquement? Professeur: Le coût de l'inaction est bien plus élevé. Madame Lacroix: Nous devons investir massivement maintenant. Animateur: Quel message aux gouvernements? Professeur: Des lois contraignantes immédiatement. Madame Lacroix: Et des sanctions pour les pollueurs. Animateur: Merci pour ces éclairages passionnants.","transcript_en":"Host: Welcome to our debate on the environment. Our guests are Professor Dubois and Mrs. Lacroix. Professor: Thank you for having us. Mrs. Lacroix: It's an honor to be here. Host: Let's start with the climate emergency. Professor: We no longer have time to wait. Mrs. Lacroix: I agree, every year counts. Host: What solutions do you propose? Professor: Drastic reduction of carbon emissions. Mrs. Lacroix: And a rapid energy transition. Host: Is this economically realistic? Professor: The cost of inaction is much higher. Mrs. Lacroix: We must invest massively now. Host: What message to governments? Professor: Binding laws immediately. Mrs. Lacroix: And sanctions for polluters. Host: Thank you for these fascinating insights.","points":[{"point":1,"male_lines":["Bienvenue à notre débat sur l'environnement. Nos invités sont le professeur Dubois et Madame Lacroix.","Commençons par l'urgence climatique.","Quelles solutions proposez-vous?"],"female_lines":["Merci de nous accueillir.","C'est un honneur d'être ici.","Nous n'avons plus le temps d'attendre."]},{"point":2,"male_lines":["Je suis d'accord, chaque année compte."],"female_lines":["La réduction drastique des émissions de carbone.","Et une transition énergétique rapide."]},{"point":3,"male_lines":["Est-ce réaliste économiquement?","Quel message aux gouvernements?"],"female_lines":["Le coût de l'inaction est bien plus élevé.","Nous devons investir massivement maintenant."]},{"point":4,"male_lines":["Des lois contraignantes immédiatement.","Merci pour ces éclairages passionnants."],"female_lines":["Et des sanctions pour les pollueurs."]}]},{"id":32,"section":"G","theme":"Healthcare system","question":"Quel problème du système de santé est principalement discuté ?","options":[{"id":"A","text":"Le manque de médecins","image_prompt":"Doctor shortage"},{"id":"B","text":"Les temps d'attente","image_prompt":"Waiting times"},{"id":"C","text":"Le financement","image_prompt":"Healthcare funding"},{"id":"D","text":"La technologie médicale","image_prompt":"Medical technology"}],"correct":1,"transcript_fr":"Présentateur: Notre sujet du jour: les délais dans le système de santé. Docteur Martin: C'est une crise majeure. Infirmière Tremblay: Les patients attendent des mois. Présentateur: Pourquoi cette situation? Docteur Martin: Manque de personnel et de ressources. Infirmière Tremblay: Et une population vieillissante. Présentateur: Quelles conséquences? Docteur Martin: Des diagnostics tardifs. Infirmière Tremblay: Et des souffrances évitables. Présentateur: Des solutions à proposer? Docteur Martin: Recruter à l'international. Infirmière Tremblay: Et optimiser les procédures administratives. Présentateur: Le gouvernement écoute-t-il? Docteur Martin: Les promesses sont nombreuses. Infirmière Tremblay: Mais les actions tardent à venir. Présentateur: Merci pour votre témoignage.","transcript_en":"Presenter: Our topic today: delays in the healthcare system. Dr. Martin: It's a major crisis. Nurse Tremblay: Patients wait for months. Presenter: Why this situation? Dr. Martin: Lack of staff and resources. Nurse Tremblay: And an aging population. Presenter: What consequences? Dr. Martin: Late diagnoses. Nurse Tremblay: And avoidable suffering. Presenter: Any solutions to propose? Dr. Martin: Recruit internationally. Nurse Tremblay: And optimize administrative procedures. Presenter: Is the government listening? Dr. Martin: Promises are numerous. Nurse Tremblay: But actions are slow to come. Presenter: Thank you for your testimony.","points":[{"point":1,"male_lines":["Notre sujet du jour: les délais dans le système de santé.","Pourquoi cette situation?","Quelles conséquences?"],"female_lines":["C'est une crise majeure.","Les patients attendent des mois.","Manque de personnel et de ressources."]},{"point":2,"male_lines":["Et une population vieillissante."],"female_lines":["Des diagnostics tardifs.","Et des souffrances évitables."]},{"point":3,"male_lines":["Des solutions à proposer?","Le gouvernement écoute-t-il?"],"female_lines":["Recruter à l'international.","Et optimiser les procédures administratives."]},{"point":4,"male_lines":["Les promesses sont nombreuses.","Merci pour votre témoignage."],"female_lines":["Mais les actions tardent à venir."]}]},{"id":33,"section":"G","theme":"Digital privacy","question":"Quelle est la préoccupation principale exprimée ?","options":[{"id":"A","text":"Le vol d'identité","image_prompt":"Identity theft"},{"id":"B","text":"La surveillance gouvernementale","image_prompt":"Government surveillance"},{"id":"C","text":"Les entreprises technologiques","image_prompt":"Tech companies"},{"id":"D","text":"Les cyberattaques","image_prompt":"Cyber attacks"}],"correct":2,"transcript_fr":"Journaliste: Nos données personnelles sont-elles en sécurité? Expert Roy: Malheureusement non. Avocate Gagnon: Les géants du web nous exploitent. Journaliste: Comment cela se manifeste-t-il? Expert Roy: Ils revendent nos informations. Avocate Gagnon: Sans notre consentement éclairé. Journaliste: Est-ce légal? Expert Roy: Dans une zone grise législative. Avocate Gagnon: Les lois datent d'une autre époque. Journaliste: Que conseillez-vous aux citoyens? Expert Roy: Lire attentivement les conditions d'utilisation. Avocate Gagnon: Et utiliser des outils de protection. Journaliste: L'État doit-il intervenir? Expert Roy: Une réglementation stricte est nécessaire. Avocate Gagnon: Avec des amendes dissuasives. Journaliste: Merci pour ces précieux conseils.","transcript_en":"Journalist: Are our personal data safe? Expert Roy: Unfortunately not. Lawyer Gagnon: Web giants exploit us. Journalist: How does this manifest? Expert Roy: They resell our information. Lawyer Gagnon: Without our informed consent. Journalist: Is this legal? Expert Roy: In a legislative gray area. Lawyer Gagnon: Laws date from another era. Journalist: What do you advise citizens? Expert Roy: Read terms of use carefully. Lawyer Gagnon: And use protection tools. Journalist: Should the State intervene? Expert Roy: Strict regulation is necessary. Lawyer Gagnon: With dissuasive fines. Journalist: Thank you for these valuable tips.","points":[{"point":1,"male_lines":["Nos données personnelles sont-elles en sécurité?","Comment cela se manifeste-t-il?","Est-ce légal?"],"female_lines":["Malheureusement non.","Les géants du web nous exploitent.","Ils revendent nos informations."]},{"point":2,"male_lines":["Sans notre consentement éclairé."],"female_lines":["Dans une zone grise législative.","Les lois datent d'une autre époque."]},{"point":3,"male_lines":["Que conseillez-vous aux citoyens?","L'État doit-il intervenir?"],"female_lines":["Lire attentivement les conditions d'utilisation.","Et utiliser des outils de protection."]},{"point":4,"male_lines":["Une réglementation stricte est nécessaire.","Merci pour ces précieux conseils."],"female_lines":["Avec des amendes dissuasives."]}]},{"id":34,"section":"G","theme":"Indigenous rights","question":"Quelle revendication est au centre du débat ?","options":[{"id":"A","text":"L'autonomie territoriale","image_prompt":"Territorial autonomy"},{"id":"B","text":"La préservation des langues","image_prompt":"Language preservation"},{"id":"C","text":"La consultation obligatoire","image_prompt":"Mandatory consultation"},{"id":"D","text":"Les réparations historiques","image_prompt":"Historical reparations"}],"correct":0,"transcript_fr":"Modérateur: Bienvenue à ce forum sur les droits autochtones. Chef Simon: Merci pour cette tribune. Professeur Bergeron: C'est un sujet crucial. Modérateur: Quelle est votre revendication principale? Chef Simon: La reconnaissance de notre autonomie territoriale. Professeur Bergeron: Sur les terres ancestrales traditionnelles. Modérateur: Quels obstacles rencontrez-vous? Chef Simon: La lenteur des négociations gouvernementales. Professeur Bergeron: Et l'opposition de certaines industries. Modérateur: Quel avenir envisagez-vous? Chef Simon: Une co-gestion des ressources naturelles. Professeur Bergeron: Avec respect des traités historiques. Modérateur: Un message aux Québécois? Chef Simon: Comprendre notre histoire partagée. Professeur Bergeron: Et construire des ponts ensemble. Modérateur: Merci pour cette discussion enrichissante.","transcript_en":"Moderator: Welcome to this forum on Indigenous rights. Chief Simon: Thank you for this platform. Professor Bergeron: It's a crucial subject. Moderator: What is your main claim? Chief Simon: Recognition of our territorial autonomy. Professor Bergeron: On traditional ancestral lands. Moderator: What obstacles do you face? Chief Simon: The slowness of government negotiations. Professor Bergeron: And opposition from certain industries. Moderator: What future do you envision? Chief Simon: Co-management of natural resources. Professor Bergeron: With respect for historical treaties. Moderator: A message to Quebecers? Chief Simon: Understand our shared history. Professor Bergeron: And build bridges together. Moderator: Thank you for this enriching discussion.","points":[{"point":1,"male_lines":["Bienvenue à ce forum sur les droits autochtones.","Quelle est votre revendication principale?","Quels obstacles rencontrez-vous?"],"female_lines":["Merci pour cette tribune.","C'est un sujet crucial.","La reconnaissance de notre autonomie territoriale."]},{"point":2,"male_lines":["Sur les terres ancestrales traditionnelles."],"female_lines":["La lenteur des négociations gouvernementales.","Et l'opposition de certaines industries."]},{"point":3,"male_lines":["Quel avenir envisagez-vous?","Un message aux Québécois?"],"female_lines":["Une co-gestion des ressources naturelles.","Avec respect des traités historiques."]},{"point":4,"male_lines":["Comprendre notre histoire partagée.","Merci pour cette discussion enrichissante."],"female_lines":["Et construire des ponts ensemble."]}]},{"id":35,"section":"G","theme":"Artificial intelligence ethics","question":"Quel dilemme éthique est soulevé ?","options":[{"id":"A","text":"Le remplacement des emplois","image_prompt":"Job replacement AI"},{"id":"B","text":"La prise de décision autonome","image_prompt":"Autonomous decision making"},{"id":"C","text":"La créativité artificielle","image_prompt":"AI creativity"},{"id":"D","text":"La surveillance prédictive","image_prompt":"Predictive surveillance"}],"correct":1,"transcript_fr":"Animateur: L'intelligence artificielle pose des défis éthiques majeurs. Docteur Chen: Absolument, surtout concernant l'autonomie. Philosophe Morin: Qui est responsable des décisions des algorithmes? Animateur: Pouvez-vous donner un exemple? Docteur Chen: Une voiture autonome doit-elle sauver le passager ou le piéton? Philosophe Morin: Impossible de programmer la morale universelle. Animateur: Quelles sont les implications? Docteur Chen: Une responsabilité légale floue. Philosophe Morin: Et une confiance publique fragile. Animateur: Comment réguler cela? Docteur Chen: Des comités d'éthique obligatoires. Philosophe Morin: Et une transparence totale des algorithmes. Animateur: L'avenir nous dira si nous réussissons.","transcript_en":"Host: Artificial intelligence poses major ethical challenges. Dr. Chen: Absolutely, especially regarding autonomy. Philosopher Morin: Who is responsible for algorithm decisions? Host: Can you give an example? Dr. Chen: Should an autonomous car save the passenger or the pedestrian? Philosopher Morin: Impossible to program universal morality. Host: What are the implications? Dr. Chen: Blurred legal responsibility. Philosopher Morin: And fragile public trust. Host: How to regulate this? Dr. Chen: Mandatory ethics committees. Philosopher Morin: And total algorithm transparency. Host: The future will tell if we succeed.","points":[{"point":1,"male_lines":["L'intelligence artificielle pose des défis éthiques majeurs.","Pouvez-vous donner un exemple?","Quelles sont les implications?"],"female_lines":["Absolument, surtout concernant l'autonomie.","Qui est responsable des décisions des algorithmes?","Une voiture autonome doit-elle sauver le passager ou le piéton?"]},{"point":2,"male_lines":["Impossible de programmer la morale universelle."],"female_lines":["Une responsabilité légale floue.","Et une confiance publique fragile."]},{"point":3,"male_lines":["Comment réguler cela?"],"female_lines":["Des comités d'éthique obligatoires.","Et une transparence totale des algorithmes."]},{"point":4,"male_lines":["L'avenir nous dira si nous réussissons."],"female_lines":[]}]},{"id":36,"section":"H","theme":"Philosophy of happiness","question":"Quelle conception du bonheur est défendue ?","options":[{"id":"A","text":"Le bonheur par l'accomplissement","image_prompt":"Happiness through achievement"},{"id":"B","text":"Le bonheur par la simplicité","image_prompt":"Happiness through simplicity"},{"id":"C","text":"Le bonheur relationnel","image_prompt":"Relational happiness"},{"id":"D","text":"Le bonheur par la connaissance","image_prompt":"Happiness through knowledge"}],"correct":0,"transcript_fr":"Conférencier: Le bonheur n'est pas un état permanent mais une quête. Philosophe Rousseau: Une quête d'accomplissement personnel. Psychologue Lavoie: Et de réalisation de soi. Conférencier: Comment définir cet accomplissement? Philosophe Rousseau: Par l'alignement de nos actions et nos valeurs. Psychologue Lavoie: Et le dépassement de nos limites. Conférencier: Le matérialisme y contribue-t-il? Philosophe Rousseau: Non, les biens matériels sont éphémères. Psychologue Lavoie: L'accomplissement est intérieur. Conférencier: Quelle pratique recommandez-vous? Philosophe Rousseau: La méditation philosophique quotidienne. Psychologue Lavoie: Et l'établissement d'objectifs significatifs. Conférencier: Merci pour ces perspectives éclairantes.","transcript_en":"Speaker: Happiness is not a permanent state but a quest. Philosopher Rousseau: A quest for personal accomplishment. Psychologist Lavoie: And self-realization. Speaker: How to define this accomplishment? Philosopher Rousseau: By the alignment of our actions and values. Psychologist Lavoie: And surpassing our limits. Speaker: Does materialism contribute to it? Philosopher Rousseau: No, material goods are ephemeral. Psychologist Lavoie: Accomplishment is internal. Speaker: What practice do you recommend? Philosopher Rousseau: Daily philosophical meditation. Psychologist Lavoie: And establishing meaningful goals. Speaker: Thank you for these enlightening perspectives.","points":[{"point":1,"male_lines":["Le bonheur n'est pas un état permanent mais une quête.","Comment définir cet accomplissement?","Le matérialisme y contribue-t-il?"],"female_lines":["Une quête d'accomplissement personnel.","Et de réalisation de soi.","Par l'alignement de nos actions et nos valeurs."]},{"point":2,"male_lines":["Et le dépassement de nos limites."],"female_lines":["Non, les biens matériels sont éphémères.","L'accomplissement est intérieur."]},{"point":3,"male_lines":["Quelle pratique recommandez-vous?"],"female_lines":["La méditation philosophique quotidienne.","Et l'établissement d'objectifs significatifs."]},{"point":4,"male_lines":["Merci pour ces perspectives éclairantes."],"female_lines":[]}]},{"id":37,"section":"H","theme":"Economic inequality","question":"Quelle solution est proposée pour réduire les inégalités ?","options":[{"id":"A","text":"L'impôt sur la fortune","image_prompt":"Wealth tax"},{"id":"B","text":"L'éducation gratuite","image_prompt":"Free education"},{"id":"C","text":"Le revenu universel","image_prompt":"Universal basic income"},{"id":"D","text":"Le contrôle des loyers","image_prompt":"Rent control"}],"correct":2,"transcript_fr":"Économiste: Les inégalités économiques s'accélèrent dangereusement. Sociologue Dupont: Il faut une redistribution radicale. Économiste: Quelle forme prendrait-elle? Sociologue Dupont: Un revenu universel inconditionnel. Économiste: Financièrement viable? Sociologue Dupont: En réformant le système fiscal actuel. Économiste: Les effets pervers? Sociologue Dupont: Des études montrent une réduction de la pauvreté. Économiste: Et la motivation au travail? Sociologue Dupont: Les gens cherchent toujours l'accomplissement. Économiste: L'opinion publique? Sociologue Dupont: De plus en plus favorable. Économiste: Un défi politique majeur. Sociologue Dupont: Mais une nécessité démocratique.","transcript_en":"Economist: Economic inequalities are dangerously accelerating. Sociologist Dupont: We need radical redistribution. Economist: What form would it take? Sociologist Dupont: An unconditional universal income. Economist: Financially viable? Sociologist Dupont: By reforming the current tax system. Economist: The side effects? Sociologist Dupont: Studies show a reduction in poverty. Economist: And motivation to work? Sociologist Dupont: People still seek accomplishment. Economist: Public opinion? Sociologist Dupont: Increasingly favorable. Economist: A major political challenge. Sociologist Dupont: But a democratic necessity.","points":[{"point":1,"male_lines":["Les inégalités économiques s'accélèrent dangereusement.","Quelle forme prendrait-elle?","Financièrement viable?"],"female_lines":["Il faut une redistribution radicale.","Un revenu universel inconditionnel.","En réformant le système fiscal actuel."]},{"point":2,"male_lines":["Les effets pervers?","Et la motivation au travail?"],"female_lines":["Des études montrent une réduction de la pauvreté.","Les gens cherchent toujours l'accomplissement."]},{"point":3,"male_lines":["L'opinion publique?","Un défi politique majeur."],"female_lines":["De plus en plus favorable.","Mais une nécessité démocratique."]}]},{"id":38,"section":"H","theme":"Memory and identity","question":"Quel lien entre mémoire et identité est exploré ?","options":[{"id":"A","text":"La mémoire collective","image_prompt":"Collective memory"},{"id":"B","text":"La mémoire traumatique","image_prompt":"Traumatic memory"},{"id":"C","text":"La mémoire autobiographique","image_prompt":"Autobiographical memory"},{"id":"D","text":"La mémoire génétique","image_prompt":"Genetic memory"}],"correct":2,"transcript_fr":"Chercheur: Notre identité est construite sur nos souvenirs. Neuroscientifique Blanc: La mémoire autobiographique est fondamentale. Chercheur: Comment se forme-t-elle? Neuroscientifique Blanc: À travers les récits familiaux répétés. Chercheur: Et les souvenirs faux? Neuroscientifique Blanc: Ils façonnent aussi notre identité. Chercheur: La maladie d'Alzheimer? Neuroscientifique Blanc: Une perte progressive de soi. Chercheur: Peut-on recréer des souvenirs? Neuroscientifique Blanc: C'est éthiquement délicat. Chercheur: L'avenir de la mémoire artificielle? Neuroscientifique Blanc: Des implants pourraient aider. Chercheur: Une frontière à ne pas franchir? Neuroscientifique Blanc: Modifier l'identité fondamentale.","transcript_en":"Researcher: Our identity is built on our memories. Neuroscientist Blanc: Autobiographical memory is fundamental. Researcher: How does it form? Neuroscientist Blanc: Through repeated family narratives. Researcher: And false memories? Neuroscientist Blanc: They also shape our identity. Researcher: Alzheimer's disease? Neuroscientist Blanc: A progressive loss of self. Researcher: Can we recreate memories? Neuroscientist Blanc: It's ethically delicate. Researcher: The future of artificial memory? Neuroscientist Blanc: Implants could help. Researcher: A line not to cross? Neuroscientist Blanc: Modifying fundamental identity.","points":[{"point":1,"male_lines":["Notre identé est construite sur nos souvenirs.","Comment se forme-t-elle?","Et les souvenirs faux?"],"female_lines":["La mémoire autobiographique est fondamentale.","À travers les récits familiaux répétés.","Ils façonnent aussi notre identité."]},{"point":2,"male_lines":["La maladie d'Alzheimer?","Peut-on recréer des souvenirs?"],"female_lines":["Une perte progressive de soi.","C'est éthiquement délicat."]},{"point":3,"male_lines":["L'avenir de la mémoire artificielle?","Une frontière à ne pas franchir?"],"female_lines":["Des implants pourraient aider.","Modifier l'identité fondamentale."]}]},{"id":39,"section":"H","theme":"Post-colonial literature","question":"Quel thème domine l'analyse littéraire ?","options":[{"id":"A","text":"L'hybridité culturelle","image_prompt":"Cultural hybridity"},{"id":"B","text":"La résistance politique","image_prompt":"Political resistance"},{"id":"C","text":"La nostalgie","image_prompt":"Nostalgia theme"},{"id":"D","text":"L'exil","image_prompt":"Exile theme"}],"correct":0,"transcript_fr":"Critique: La littérature post-coloniale québécoise évolue constamment. Auteur Césaire: Elle explore l'entre-deux culturel. Critique: Définissez cette hybridité. Auteur Césaire: Le mélange de l'héritage français et des racines locales. Critique: C'est une richesse? Auteur Césaire: Une complexité parfois douloureuse. Critique: Comment l'exprimez-vous? Auteur Césaire: Par des personages tiraillés entre deux mondes. Critique: Le français comme outil de libération? Auteur Césaire: Et parfois d'aliénation. Critique: Votre message aux jeunes écrivains? Auteur Césaire: Écrivez votre vérité multiple. Critique: Sans compromis? Auteur Césaire: L'authenticité avant tout.","transcript_en":"Critic: Post-colonial Quebec literature is constantly evolving. Author Césaire: It explores the cultural in-between. Critic: Define this hybridity. Author Césaire: The blend of French heritage and local roots. Critic: Is it a richness? Author Césaire: A sometimes painful complexity. Critic: How do you express it? Author Césaire: Through characters torn between two worlds. Critic: French as a tool of liberation? Author Césaire: And sometimes of alienation. Critic: Your message to young writers? Author Césaire: Write your multiple truth. Critic: Without compromise? Author Césaire: Authenticity above all.","points":[{"point":1,"male_lines":["La littérature post-coloniale québécoise évolue constamment.","Définissez cette hybridité.","C'est une richesse?"],"female_lines":["Elle explore l'entre-deux culturel.","Le mélange de l'héritage français et des racines locales.","Une complexité parfois douloureuse."]},{"point":2,"male_lines":["Comment l'exprimez-vous?","Le français comme outil de libération?"],"female_lines":["Par des personages tiraillés entre deux mondes.","Et parfois d'aliénation."]},{"point":3,"male_lines":["Votre message aux jeunes écrivains?","Sans compromis?"],"female_lines":["Écrivez votre vérité multiple.","L'authenticité avant tout."]}]},{"id":40,"section":"H","theme":"Quantum physics implications","question":"Quelle conséquence philosophique de la physique quantique est discutée ?","options":[{"id":"A","text":"Le déterminisme","image_prompt":"Determinism concept"},{"id":"B","text":"Le libre arbitre","image_prompt":"Free will concept"},{"id":"C","text":"La nature de la réalité","image_prompt":"Nature of reality"},{"id":"D","text":"Le temps et l'espace","image_prompt":"Time and space"}],"correct":2,"transcript_fr":"Physicien: La mécanique quantique remet en cause notre vision du monde. Philosophe Martin: La réalité n'existe pas indépendamment de l'observation. Physicien: Expliquez ce paradoxe. Philosophe Martin: L'observateur influence le phénomène observé. Physicien: C'est contre-intuitif. Philosophe Martin: Notre intuition classique est limitée. Physicien: Des implications pour la conscience? Philosophe Martin: Peut-être que la conscience joue un rôle fondamental. Physicien: Le multivers alors? Philosophe Martin: Une interprétation parmi d'autres. Physicien: Quelle certitude nous reste-t-il? Philosophe Martin: Que nous ne comprenons pas encore tout. Physicien: Une humilité scientifique nécessaire. Philosophe Martin: Et une ouverture philosophique.","transcript_en":"Physicist: Quantum mechanics challenges our worldview. Philosopher Martin: Reality does not exist independently of observation. Physicist: Explain this paradox. Philosopher Martin: The observer influences the observed phenomenon. Physicist: It's counter-intuitive. Philosopher Martin: Our classical intuition is limited. Physicist: Implications for consciousness? Philosopher Martin: Perhaps consciousness plays a fundamental role. Physicist: The multiverse then? Philosopher Martin: One interpretation among others. Physicist: What certainty remains for us? Philosopher Martin: That we don't understand everything yet. Physicist: A necessary scientific humility. Philosopher Martin: And a philosophical openness.","points":[{"point":1,"male_lines":["La mécanique quantique remet en cause notre vision du monde.","Expliquez ce paradoxe.","C'est contre-intuitif."],"female_lines":["La réalité n'existe pas indépendamment de l'observation.","L'observateur influence le phénomène observé.","Notre intuition classique est limitée."]},{"point":2,"male_lines":["Des implications pour la conscience?","Le multivers alors?"],"female_lines":["Peut-être que la conscience joue un rôle fondamental.","Une interprétation parmi d'autres."]},{"point":3,"male_lines":["Quelle certitude nous reste-t-il?","Une humilité scientifique nécessaire."],"female_lines":["Que nous ne comprenons pas encore tout.","Et une ouverture philosophique."]}]}]`);export{e as default};
